// Get data from AI analysis
const aiData = $input.first().json;
const siteUrl = aiData.siteUrl;
const siteName = aiData.siteName;
const sectionIds = aiData.sectionIds || [];

// ⚠️ REPLACE WITH YOUR SCREENSHOTONE API KEY
const API_KEY = 'uSYTkX5PDESZnQ';
const timestamp = new Date().toISOString().split('T')[0];

// Base screenshots (always include)
const screenshots = [
  {
    name: 'hero',
    description: 'Hero section (above the fold)',
    viewport_width: 1920,
    viewport_height: 1080,
    device_scale_factor: 2,
    format: 'png'
  },
  {
    name: 'fullpage',
    description: 'Full page screenshot',
    full_page: true,
    viewport_width: 1920,
    device_scale_factor: 2,
    format: 'png'
  }
];

// Add REAL section IDs from Firecrawl rendered HTML
if (sectionIds.length > 0) {
  sectionIds.forEach((sectionId) => {
    const cleanName = sectionId.replace(/[^a-zA-Z0-9]/g, '_').toLowerCase();
    const displayName = sectionId.charAt(0).toUpperCase() + sectionId.slice(1).replace(/[-_]/g, ' ');

    screenshots.push({
      name: `section_${cleanName}`,
      description: `${displayName} section`,
      scroll_into_view: `#${sectionId}`,
      error_on_selector_not_found: true,
      viewport_width: 1920,
      viewport_height: 1080,
      device_scale_factor: 2,
      format: 'png'
    });
  });
}

// Mobile at the end
screenshots.push({
  name: 'mobile',
  description: 'Mobile version',
  viewport_mobile: true,
  viewport_width: 375,
  viewport_height: 812,
  device_scale_factor: 2,
  format: 'png'
});

// Build API URLs
const screenshotConfigs = screenshots.map(shot => {
  const ext = shot.format || 'png';
  const filename = `${siteName}_${shot.name}_${timestamp}.${ext}`;

  const params = {
    access_key: API_KEY,
    url: siteUrl,
    format: 'png',
    viewport_width: shot.viewport_width || 1920,
    viewport_height: shot.viewport_height || 1080,
    device_scale_factor: shot.device_scale_factor || 2,
    block_cookie_banners: true,
    block_chats: true,
    block_ads: true,
    delay: 3
  };

  if (shot.full_page) params.full_page = true;
  if (shot.viewport_mobile) params.viewport_mobile = true;
  if (shot.scroll_into_view) params.scroll_into_view = shot.scroll_into_view;
  if (shot.error_on_selector_not_found) params.error_on_selector_not_found = true;

  const queryString = Object.entries(params)
    .map(([key, value]) => `${encodeURIComponent(key)}=${encodeURIComponent(value)}`)
    .join('&');

  return {
    siteName,
    baseUrl: siteUrl,
    screenshotName: shot.name,
    description: shot.description,
    filename,
    format: ext,
    apiUrl: `https://api.screenshotone.com/take?${queryString}`,
    aiAnalysis: aiData,
    usedSectionIds: sectionIds.length > 0,
    totalScreenshots: screenshots.length
  };
});

return screenshotConfigs.map(config => ({ json: config }));

// Get original config data
const config = $('Site Configuration').item.json;
const inputItem = $input.item;

// Check if screenshot succeeded
// 1. Must have binary data
const hasBinary = inputItem.binary && Object.keys(inputItem.binary).length > 0;

// 2. Check for API error responses
const hasJsonError = inputItem.json.is_successful === false || 
                    inputItem.json.error_code || 
                    inputItem.json.error_message;

// 3. Check if binary is actually an image (not error JSON saved as file)
let isValidImage = false;
if (hasBinary) {
  const binaryKey = Object.keys(inputItem.binary)[0];
  const binaryData = inputItem.binary[binaryKey];
  // Check mime type - should be image/png
  isValidImage = binaryData.mimeType && binaryData.mimeType.startsWith('image/');
}

if (!hasBinary || hasJsonError || !isValidImage) {
  // Skip failed screenshots
  return [];
}

// Return both json data AND binary
return {
  json: {
    siteName: config.siteName,
    baseUrl: config.baseUrl,
    screenshotName: config.screenshotName,
    description: config.description,
    filename: config.filename,
    format: config.format,
    success: true
  },
  binary: inputItem.binary
};

const items = $input.all();

// Get data from Site Configuration
const configItems = $('Site Configuration').all();
const firstConfig = configItems[0].json;
const siteName = firstConfig.siteName;
const baseUrl = firstConfig.baseUrl;

// Get AI analysis data
const aiAnalysis = firstConfig.aiAnalysis;
const sectionIds = aiAnalysis.sectionIds || [];
const detectedIds = aiAnalysis.detectedIds || [];

// Get Merge Screenshot Data items (only successful ones)
const mergeItems = $('Merge Screenshot Data').all();

// Map screenshots with Drive URLs
const screenshots = items.map((item, index) => {
  const mergeItem = mergeItems[index]?.json || {};
  return {
    name: mergeItem.screenshotName || `screenshot_${index + 1}`,
    description: mergeItem.description || '',
    filename: mergeItem.filename || '',
    driveUrl: item.json.webViewLink,
    driveId: item.json.id
  };
});

// Count successful vs total attempted
const totalAttempted = configItems.length;
const totalSuccessful = screenshots.length;

// Build row for Google Sheets
const sheetsRow = {
  siteName,
  url: baseUrl,
  timestamp: new Date().toISOString(),

  // AI Analysis
  blocks_count: aiAnalysis.blocks_count,
  blocks_list: aiAnalysis.blocks_list,
  has_blog: aiAnalysis.has_blog,
  languages: aiAnalysis.languages,
  site_topic: aiAnalysis.site_topic,
  specialization: aiAnalysis.specialization,
  target_audience: aiAnalysis.target_audience,
  key_services: aiAnalysis.key_services,

  // Screenshot info - Firecrawl edition
  screenshot_method: 'Firecrawl Rendered HTML',
  detected_ids: detectedIds.join(', ') || 'none',
  section_ids_used: sectionIds.join(', ') || 'none',
  screenshots_attempted: totalAttempted,
  screenshots_successful: totalSuccessful
};

// Add screenshot URLs dynamically
screenshots.forEach((s, i) => {
  sheetsRow[`img_${i + 1}_${s.name}`] = s.driveUrl || '';
});

return [{
  json: {
    ...sheetsRow,
    screenshots,
    screenshotCount: totalSuccessful,
    sectionIds,
    detectedIds
  }
}];

