// Get AI response
const response = $input.first().json;
const prevData = $('Prepare AI Request').first().json;
const aiContent = response.choices[0].message.content;

// Parse JSON
let analysis = {};
try {
  const jsonMatch = aiContent.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    analysis = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  analysis = {
    blocks_count: 5,
    blocks_list: 'Error parsing',
    has_blog: false,
    languages: 'N/A',
    site_topic: 'Could not analyze',
    specialization: 'N/A',
    target_audience: 'N/A',
    key_services: 'N/A',
    section_ids: []
  };
}

// Get validated section IDs from AI
let sectionIds = analysis.section_ids || [];
if (typeof sectionIds === 'string') {
  sectionIds = sectionIds.split(',').map(a => a.trim()).filter(a => a);
}

// Clean IDs - remove # if present
sectionIds = sectionIds
  .map(id => id.replace(/^#/, '').trim())
  .filter(id => id && id.length > 0);

// If AI found no sections, use detected IDs as fallback (max 10)
if (sectionIds.length === 0 && prevData.detectedIds?.length > 0) {
  sectionIds = prevData.detectedIds.slice(0, 10);
}

return [{
  json: {
    siteUrl: prevData.siteUrl,
    siteName: prevData.siteName,
    blocks_count: String(analysis.blocks_count || 'N/A'),
    blocks_list: String(analysis.blocks_list || 'N/A'),
    has_blog: analysis.has_blog ? 'Yes' : 'No',
    languages: String(analysis.languages || 'N/A'),
    site_topic: String(analysis.site_topic || 'N/A'),
    specialization: String(analysis.specialization || 'N/A'),
    target_audience: String(analysis.target_audience || 'N/A'),
    key_services: String(analysis.key_services || 'N/A'),
    // Real section IDs from rendered HTML
    sectionIds: sectionIds,
    detectedIds: prevData.detectedIds || [],
    firecrawlSuccess: prevData.firecrawlSuccess
  }
}];

// Get rendered HTML from Firecrawl
const firecrawlResponse = $input.first().json;
const formData = $('Portfolio Form').first().json;
let inputUrl = formData['Website URL'];

// Add https:// if missing
const siteUrl = inputUrl.startsWith('http') ? inputUrl : 'https://' + inputUrl;

// Extract site name from domain
let siteName = siteUrl
  .replace(/^https?:\/\//, '')
  .replace(/^www\./, '')
  .split('/')[0]
  .split('.')[0];

// Get rendered HTML from Firecrawl
const html = firecrawlResponse.data?.html || firecrawlResponse.html || '';

// EXTRACT REAL SECTION IDs from rendered HTML
// This regex finds all id attributes in the HTML
const idMatches = html.match(/id=["']([^"']+)["']/gi) || [];
const allIds = idMatches.map(m => m.match(/id=["']([^"']+)["']/i)?.[1]).filter(Boolean);

// Filter to likely section IDs (exclude utility IDs)
const excludePatterns = /^(root|app|__next|__nuxt|gatsby|webpack|modal|tooltip|dropdown|menu|nav|header|footer|sidebar|cookie|banner|popup|overlay|backdrop)/i;
const sectionIds = allIds.filter(id => {
  // Keep IDs that look like sections
  if (excludePatterns.test(id)) return false;
  if (id.length < 2 || id.length > 50) return false;
  if (/^[0-9]/.test(id)) return false; // Skip IDs starting with numbers
  return true;
});

// Remove duplicates
const uniqueSectionIds = [...new Set(sectionIds)];

// Clean and truncate HTML for AI analysis
const cleanHtml = html
  .substring(0, 25000)
  .replace(/[\x00-\x1F\x7F]/g, ' ')
  .replace(/\\/g, '\\\\')
  .replace(/"/g, "'");

const requestBody = {
  model: 'gpt-4o-mini',
  temperature: 0.2,
  max_tokens: 2000,
  messages: [
    {
      role: 'system',
      content: `You are a website analyst. Analyze the rendered HTML and identify which section IDs are actual page sections worth screenshotting.\n\nYou will receive:\n1. The rendered HTML\n2. A list of detected IDs\n\nFilter the IDs to only include real content sections (hero, about, services, features, etc).\nExclude utility elements, navigation, modals, etc.\n\nRespond ONLY with valid JSON.`
    },
    {
      role: 'user',
      content: `Analyze this website and its sections:\n\nDetected IDs: ${JSON.stringify(uniqueSectionIds)}\n\n{\n  "blocks_count": <number of main sections>,\n  "blocks_list": "<section names>",\n  "has_blog": <true/false>,\n  "languages": "<languages>",\n  "site_topic": "<about the site>",\n  "specialization": "<niche>",\n  "target_audience": "<audience>",\n  "key_services": "<services>",\n  "section_ids": ["<ONLY the IDs that are real content sections worth screenshotting, from the detected IDs list>"]\n}\n\nHTML (first 25KB):\n${cleanHtml}`
    }
  ]
};

return [{ 
  json: { 
    requestBody, 
    siteUrl, 
    siteName, 
    detectedIds: uniqueSectionIds,
    firecrawlSuccess: firecrawlResponse.success || !!firecrawlResponse.data
  } 
}];

const data = $input.first().json;

// Gather all info for Upwork portfolio
const siteInfo = {
  siteName: data.siteName,
  url: data.url,
  blocks_count: data.blocks_count,
  blocks_list: data.blocks_list,
  has_blog: data.has_blog,
  languages: data.languages,
  site_topic: data.site_topic,
  specialization: data.specialization,
  target_audience: data.target_audience,
  key_services: data.key_services,
  screenshotCount: data.screenshotCount
};

const requestBody = {
  model: 'gpt-4o-mini',
  temperature: 0.4,
  max_tokens: 800,
  messages: [
    {
      role: 'system',
      content: `You are an expert freelancer writing Upwork portfolio descriptions. Write compelling, professional content that highlights technical skills and business impact.

RULES:
1. Project title: Brief but descriptive (max 50 chars)
2. Project description: Goals, solution, impact (max 600 chars)
3. Skills: Exactly 5 relevant technical skills
4. Write in first person as the developer who built this
5. Respond ONLY in valid JSON, no markdown`
    },
    {
      role: 'user',
      content: `Based on this website analysis, create an Upwork portfolio project entry:

Website: ${siteInfo.siteName} (${siteInfo.url})
Topic: ${siteInfo.site_topic}
Specialization: ${siteInfo.specialization}
Target Audience: ${siteInfo.target_audience}
Key Services: ${siteInfo.key_services}
Sections: ${siteInfo.blocks_count} (${siteInfo.blocks_list})
Has Blog: ${siteInfo.has_blog}
Languages: ${siteInfo.languages}
Screenshots: ${siteInfo.screenshotCount}

Generate JSON:
{
  "project_title": "<max 50 chars, descriptive title>",
  "your_role": "<max 100 chars, e.g. Full-Stack Developer, Lead Designer>",
  "project_description": "<max 600 chars. Structure: 1) Project goals 2) My solution 3) Impact/results. Be specific about technologies used.>",
  "skills": ["<skill1>", "<skill2>", "<skill3>", "<skill4>", "<skill5>"]
}`
    }
  ]
};

return [{ json: { ...data, upworkRequestBody: requestBody } }];

const prevData = $('Prepare Upwork Request').first().json;
const response = $input.first().json;
const aiContent = response.choices[0].message.content;

// Parse JSON
let upwork = {};
try {
  const jsonMatch = aiContent.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    upwork = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  upwork = {
    project_title: 'Portfolio Website Development',
    your_role: 'Full-Stack Developer',
    project_description: 'Error parsing AI response',
    skills: ['Web Development', 'JavaScript', 'CSS', 'HTML', 'Responsive Design']
  };
}

// Ensure 5 skills
let skills = upwork.skills || [];
if (typeof skills === 'string') skills = skills.split(',').map(s => s.trim());
skills = skills.slice(0, 5);
while (skills.length < 5) skills.push('Web Development');

// Build result
const result = {
  siteName: prevData.siteName,
  url: prevData.url,
  timestamp: prevData.timestamp,
  blocks_count: prevData.blocks_count,
  blocks_list: prevData.blocks_list,
  has_blog: prevData.has_blog,
  languages: prevData.languages,
  site_topic: prevData.site_topic,
  specialization: prevData.specialization,
  target_audience: prevData.target_audience,
  key_services: prevData.key_services,
  screenshot_method: prevData.screenshot_method,
  ai_found_anchors: prevData.ai_found_anchors,
  anchors_checked: prevData.anchors_checked,
  screenshots_attempted: prevData.screenshots_attempted,
  screenshots_successful: prevData.screenshots_successful,

  // Upwork
  upwork_title: (upwork.project_title || '').substring(0, 50),
  upwork_role: (upwork.your_role || '').substring(0, 100),
  upwork_description: (upwork.project_description || '').substring(0, 600),
  upwork_skills: skills.join(', '),

  screenshots: prevData.screenshots,
  screenshotCount: prevData.screenshotCount,
  aiFoundAnchors: prevData.aiFoundAnchors,
  allAnchors: prevData.allAnchors
};

// Copy dynamic screenshot columns
Object.keys(prevData).forEach(key => {
  if (key.startsWith('img_')) result[key] = prevData[key];
});

return [{ json: result }];
